import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";

function Landing() {
  const navigate = useNavigate();

  useEffect(() => {
    document.body.style.overflow = "hidden";
    return () => {
      document.body.style.overflow = "auto";
    };
  }, []);

  const handleContinue = () => {
    // default role or later selection
    localStorage.setItem("role", "admin"); // or remove if role later
    navigate("/login");
  };

  return (
    <>
      <Navbar variant="public" />

      <div className="flickr-landing">
        <div className="flickr-overlay" />

        <div className="flickr-content">
          <h1 className="flickr-title">
            🧿 RetailVision AI
          </h1>

          <p className="flickr-tagline">
            Smarter inventory. Clearer decisions.
          </p>

          <button className="flickr-cta" onClick={handleContinue}>
            Continue to Login
          </button>
        </div>
      </div>
    </>
  );
}

export default Landing;
